1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	
3	export type Step = { op: string; items?: Item[]; policy?: number; incident?: unknown };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	export type ScenarioResult = {
11	  results: Array<{ premium?: number; payout?: number; remainingCap?: number }>;
12	};
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
24	
25	const quotePremium = (items: Item[]): number =>
26	  items.reduce((total, item) => total + basePremiumFor(item), 0) + PROCESSING_FEE;
27	
28	const processStep = (step: Step) => ({ premium: quotePremium(step.items ?? []) });
29	
30	export const runScenario = (scenario: Scenario): ScenarioResult => ({
31	  results: scenario.steps.map(processStep),
32	});
33

